<script>
  import Icon from "@iconify/svelte"
  import { onMount } from "svelte";
  import { routeHref } from "../../libs/router";

  onMount(() => {
    window.addEventListener("scroll", handleScroll)
    return () => {
      window.removeEventListener("scroll", handleScroll)
    }
  })

  let active = false
  const handleScroll = () => {
    let windowTop = window.scrollY;
    if (windowTop > 50) {
      active = true;
      return;
    }
    active = false;
  }
  let current = '';
</script>

<header class:active>
  <h1>
    <a href={routeHref('/')} class:active={current === ''} on:click={() => current = ''}>
      <img src="img/moving_logo.svg" alt="무빙로고">
    </a>
  </h1>
  <ul>
    <li>
      <Icon icon="ic:round-live-tv" color="white" height="28" />
      <a href={routeHref('/now')} class:active={current === 'now'} on:click={() => current = 'now'}>현재상영작</a>
    </li>
    <li>
      <a href={routeHref('/popular')} class:active={current === 'popular'} on:click={() => current = 'popular'}>인기영화</a>
    </li>
    <li>
      <a href={routeHref('/upcoming')} class:active={current === 'upcoming'} on:click={() => current = 'upcoming'}>개봉예정작</a>
    </li>
    <li>
      <a href={routeHref('/top')} class:active={current === 'top'} on:click={() => current = 'top'}>높은평점</a>
    </li>
  </ul>
</header>
